        await env.DB.prepare("INSERT INTO media (kind,title,url,added_by,created_at,people,place,caption,taken_at) VALUES (?,?,?,?,?,?,?,?,?)").bind("photo", "", "/pic/" + key, me.name, Date.now(), people, place, caption, Date.now()).run();
