function heroActKey(){return 'heroAct:'+((window.S&&S.me&&S.me.email)||'anon');}
function heroActGet(){var t=null;try{t=JSON.parse(localStorage.getItem(heroActKey())||'null');}catch(e){}var day=new Date().toISOString().slice(0,10);if(!t||t.day!==day)t={day:day,visits:0,secs:0};return t;}
