function heroActBump(){var t=heroActGet();t.visits=(t.visits||0)+1;heroActSave(t);if(!window.__heroHB){window.__heroHB=setInterval(function(){var x=heroActGet();x.secs=(x.secs||0)+20;heroActSave(x);},20000);}return t;}
function heroActBlurb(t){var mins=Math.round((t.secs||0)/60);var v=t.visits||0;var bits=[];if(v>=3)bits.push("popped in "+v+" times today");if(mins>=15)bits.push("spent a solid "+mins+" minutes here today");if(bits.length)return bits.join(" and ");var warm=["keeping PULSE humming","holding down the fort","making this place feel alive","keeping the home fires lit"];return warm[Math.floor(Math.random()*warm.length)];}
function heroIntroText(){var t=heroActBump();return "Wow! "+monStableName()+", you've been "+heroActBlurb(t)+"!! Thank you for that, it's much appreciated!";}
function heroMatrixTo(finalPlain,done){var GL="\u30A2\u30A4\u30A6\u30A8\u30AA\u30AB\u30AD\u30AF\u30B1\u30B3\u30B5\u30B7\u30B9\u30BB\u30BD\u30CA\u30CB\u30CC\u30CD\u30CE0123456789";var n=finalPlain.length;var start=Date.now();var dur=1400;function rnd(){return GL.charAt(Math.floor(Math.random()*GL.length));}function frame(){var el=document.getElementById('heroGreet');if(!el){if(done)done();return;}var p=(Date.now()-start)/dur;if(p>1)p=1;var out="";for(var i=0;i<n;i++){var ch=finalPlain.charAt(i);if(ch===" "){out+=" ";continue;}var thr=(i/n)*0.8;if(p>=thr+0.18){var fc=ch;if(fc==="&")fc="&amp;";else if(fc==="<")fc="&lt;";else if(fc===">")fc="&gt;";out+=fc;}else{out+='<span style="color:#39ff14;text-shadow:0 0 6px #39ff14">'+rnd()+'</span>';}}el.innerHTML=out;if(p>=1){if(done)done();return;}requestAnimationFrame(frame);}requestAnimationFrame(frame);}
function heroSettle(){if(window.__heroFinished)return;window.__heroFinished=true;if(window.__heroTmr){clearTimeout(window.__heroTmr);window.__heroTmr=null;}heroMatrixTo(heroRestPlain(),function(){var gg=document.getElementById('heroGreet');if(gg)gg.innerHTML=heroRestHtml();if(typeof monFitHeader==="function")monFitHeader();});}
function heroGreetUpd(){var g=document.getElementById('heroGreet');if(!g)return;if(window.__heroIntroDone){if(!window.__heroFinished)return;g.innerHTML=heroRestHtml();if(typeof monFitHeader==="function")monFitHeader();return;}window.__heroIntroDone=true;g.textContent=heroIntroText();g.style.cursor="pointer";g.addEventListener("click",heroSettle,{once:true});g.addEventListener("touchstart",heroSettle,{once:true,passive:true});window.__heroTmr=setTimeout(heroSettle,15000);if(typeof monFitHeader==="function")monFitHeader();}
