var KING_SILENCE_DAYS=90,KING_GRACE_DAYS=30;
function kingView(){if(!(S.me&&S.me.isKing))return '<div class="card"><div class="empty">The King tab is private.</div></div>';var succ=S.succession||[];var seen=S.kingSeen?new Date(S.kingSeen).toLocaleString():'\\u2014';var claim=S.claim;var h='<div class="vhead"><h2>\\uD83D\\uDC51 King</h2><span class="stamp sm">private \\u2014 King only</span></div>';h+=(typeof forumPerms==='function'?forumPerms():'');h+='<div class="card"><h2 style="font-size:1rem">Status</h2><div class="sub">Heartbeat (last King activity): '+esc(seen)+'. Succession unlocks after '+KING_SILENCE_DAYS+' days of silence; the heir then has a '+KING_GRACE_DAYS+'-day window you can veto.</div>'+(claim?'<p style="color:var(--warn);margin-top:8px">\\u26a0 A succession claim is active by '+esc(claim.heir||'?')+'. <button class="qbtn" onclick="kingVeto()">Veto \\u2014 I am here</button></p>':'<p class="sub" style="margin-top:8px">No active claim. All is well.</p>')+'</div>';h+='<div class="card"><h2 style="font-size:1rem">Line of succession</h2><div class="sub">Each inherits only when the one before is gone. Add the email for each heir.</div><div style="margin-top:8px">';succ.forEach(function(e,i){h+='<div class="row" style="align-items:center;gap:8px;padding:4px 2px;border-bottom:1px solid var(--line)"><span style="width:22px;color:var(--dim)">'+(i+1)+'</span><span style="flex:1">'+esc(e)+'</span><button class="mini" onclick="kingSuccMove('+i+',-1)">\\u2191</button><button class="mini" onclick="kingSuccMove('+i+',1)">\\u2193</button><button class="mini warnb" onclick="kingSuccDel('+i+')">remove</button></div>';});h+='</div><div class="row" style="margin-top:8px;gap:8px"><input id="succAdd" placeholder="next heir email"><button class="go" onclick="kingSuccAdd()">Add heir</button></div></div>';h+='<div class="card"><h2 style="font-size:1rem">Letter to my heir</h2><div class="sub">A private message the next King reads when they inherit.</div><textarea id="kingLetter" rows="5" style="width:100%;margin-top:8px">'+esc(S.kingLetter||'')+'</textarea><div class="row" style="margin-top:8px"><button class="go" onclick="kingSaveLetter()">Save letter</button></div></div>';h+='<div class="card"><h2 style="font-size:1rem">Runbook \\u2014 how to run PULSE</h2><div class="sub">Deploy: double-click Deploy PULSE.cmd. Rollback: Rollback PULSE.cmd. Source of truth: GitHub jesseclemit/clemit-family + local src/index.js. Data: Cloudflare D1 (settings) + R2 (music / movies / pictures). Design + ops docs live in the project folder (CLAUDE.md, PMoP.md, KING-SUCCESSION-DESIGN.md).</div></div>';return h;}
